// components/ForecastChart.jsx
import React from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from 'chart.js';
import { Line } from 'react-chartjs-2';

ChartJS.register(
  CategoryScale, LinearScale, PointElement,
  LineElement, Title, Tooltip, Legend, Filler
);

const COLORS = ['#378ADD', '#1D9E75', '#D85A30', '#7F77DD', '#BA7517'];
const DASH_PATTERNS = [[], [6, 3], [2, 2], [8, 4], [4, 2]];

export default function ForecastChart({ cities }) {
  if (!cities.length) return null;

  const labels = cities[0]?.forecast?.map((d) => `${d.day} ${d.date}`) || [];

  const datasets = cities.map((city, i) => ({
    label: city.name,
    data: city.forecast?.map((d) => Math.round(d.high)) || [],
    borderColor: COLORS[i % COLORS.length],
    backgroundColor: COLORS[i % COLORS.length] + '18',
    borderDash: DASH_PATTERNS[i % DASH_PATTERNS.length],
    fill: false,
    tension: 0.35,
    pointRadius: 5,
    pointHoverRadius: 7,
    borderWidth: 2.5,
  }));

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: {
        callbacks: {
          label: (ctx) => ` ${ctx.dataset.label}: ${ctx.parsed.y}°C`,
        },
      },
    },
    scales: {
      y: {
        ticks: {
          callback: (v) => v + '°C',
          font: { size: 12 },
        },
        grid: { color: 'rgba(0,0,0,0.05)' },
      },
      x: {
        ticks: { font: { size: 12 } },
        grid: { display: false },
      },
    },
  };

  return (
    <div style={styles.wrapper}>
      <h3 style={styles.heading}>High temperature trend (°C)</h3>

      {/* Custom legend */}
      <div style={styles.legend}>
        {cities.map((c, i) => (
          <span key={i} style={styles.legendItem}>
            <span
              style={{ ...styles.legendDot, background: COLORS[i % COLORS.length] }}
            />
            {c.name}
          </span>
        ))}
      </div>

      <div style={{ position: 'relative', height: 260 }}>
        <Line data={{ labels, datasets }} options={options} />
      </div>
    </div>
  );
}

const styles = {
  wrapper: {
    background: '#fff',
    border: '1px solid #e8eaf0',
    borderRadius: 16,
    padding: '1.25rem',
    marginTop: 24,
  },
  heading: {
    fontSize: 14,
    fontWeight: 600,
    color: '#666',
    marginBottom: 12,
  },
  legend: { display: 'flex', flexWrap: 'wrap', gap: 14, marginBottom: 16 },
  legendItem: { display: 'flex', alignItems: 'center', gap: 6, fontSize: 13, color: '#555' },
  legendDot: { width: 12, height: 12, borderRadius: 3 },
};
